import React, { useState, useEffect } from "react";
import axios from "../api/axios";
import LocationAutocomplete from "../components/LocationAutocomplete";

const inputStyle = {
  width: "100%",
  padding: "10px 12px",
  borderRadius: "6px",
  border: "1px solid #2a2a2a",
  background: "#252525",
  color: "#fff",
  fontSize: "14px",
};

const labelStyle = {
  display: "block",
  color: "#999",
  fontSize: "12px",
  fontWeight: 600,
  marginBottom: "6px",
};

export default function AdminVenues() {
  const [venues, setVenues] = useState([]);
  const [loading, setLoading] = useState(true);
  const [currentPage, setCurrentPage] = useState(1);
  const [showForm, setShowForm] = useState(false);
  const [editingVenue, setEditingVenue] = useState(null);
  const [actioningId, setActioningId] = useState(null);
  const [submitting, setSubmitting] = useState(false);
  const [formData, setFormData] = useState({
    name: "",
    address: "",
    city: "",
    latitude: "",
    longitude: "",
    website: "",
    phone: "",
    description: "",
    capacity: "",
  });

  const itemsPerPage = 10;

  useEffect(() => {
    fetchVenues();
  }, []);

  const fetchVenues = async () => {
    try {
      setLoading(true);
      const response = await axios.get("/events/venues/");
      const venuesData = Array.isArray(response.data)
        ? response.data
        : response.data.results || [];
      setVenues(venuesData);
    } catch (error) {
      console.error("Error fetching venues:", error);
    } finally {
      setLoading(false);
    }
  };

  const handleInputChange = (e) => {
    const { name, value } = e.target;
    setFormData((prev) => ({ ...prev, [name]: value }));
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    setSubmitting(true);
    try {
      const payload = {
        name: formData.name,
        address: formData.address,
        city: formData.city,
        website: formData.website || null,
        phone: formData.phone || null,
        description: formData.description || null,
        capacity: formData.capacity ? parseInt(formData.capacity) : null,
      };
      if (formData.latitude) payload.latitude = parseFloat(formData.latitude);
      if (formData.longitude) payload.longitude = parseFloat(formData.longitude);

      if (editingVenue) {
        await axios.put(`/events/venues/${editingVenue.id}/`, payload);
      } else {
        await axios.post("/events/venues/", payload);
      }

      handleCancel();
      fetchVenues();
    } catch (error) {
      console.error("Error saving venue:", error);
      alert("Failed to save venue: " + (error.response?.data?.detail || error.message));
    } finally {
      setSubmitting(false);
    }
  };

  const handleEdit = (venue) => {
    setEditingVenue(venue);
    setFormData({
      name: venue.name,
      address: venue.address,
      city: venue.city,
      latitude: venue.latitude || "",
      longitude: venue.longitude || "",
      website: venue.website || "",
      phone: venue.phone || "",
      description: venue.description || "",
      capacity: venue.capacity || "",
    });
    setShowForm(true);
  };

  const handleDelete = async (id) => {
    if (!window.confirm("Delete this venue?")) return;
    setActioningId(id);
    try {
      await axios.delete(`/events/venues/${id}/`);
      fetchVenues();
    } catch (error) {
      alert("Failed to delete venue");
    } finally {
      setActioningId(null);
    }
  };

  const handleCancel = () => {
    setShowForm(false);
    setEditingVenue(null);
    setFormData({
      name: "",
      address: "",
      city: "",
      latitude: "",
      longitude: "",
      website: "",
      phone: "",
      description: "",
      capacity: "",
    });
  };

  const totalPages = Math.ceil(venues.length / itemsPerPage);
  const startIndex = (currentPage - 1) * itemsPerPage;
  const paginatedVenues = venues.slice(startIndex, startIndex + itemsPerPage);

  return (
    <div style={{ background: "#191919", minHeight: "100vh", padding: "32px" }}>
      <div className="max-w-7xl mx-auto">
        {/* Header */}
        <div style={{ marginBottom: "24px", display: "flex", justifyContent: "space-between", alignItems: "center" }}>
          <div>
            <h1 className="text-3xl font-bold text-white">Venues</h1>
            <p className="text-gray-500 text-sm mt-1">Manage event venues</p>
          </div>
          {!showForm && (
            <button
              onClick={() => setShowForm(true)}
              style={{
                padding: "8px 16px",
                borderRadius: "6px",
                border: "none",
                background: "#ff00e0",
                color: "#fff",
                fontSize: "13px",
                fontWeight: 600,
                cursor: "pointer",
              }}
            >
              + New Venue
            </button>
          )}
        </div>

        {/* Inline Form */}
        {showForm && (
          <div style={{ marginBottom: "24px", borderRadius: "8px", padding: "20px", background: "#1d191e", border: "1px solid #2a2a2a" }}>
            <h3 className="text-lg font-semibold text-white mb-4">
              {editingVenue ? "Edit Venue" : "Create New Venue"}
            </h3>
            <form onSubmit={handleSubmit}>
              <div style={{ display: "grid", gridTemplateColumns: "1fr 1fr", gap: "16px", marginBottom: "16px" }}>
                <div style={{ gridColumn: "1 / -1" }}>
                  <label style={labelStyle}>Venue Name *</label>
                  <input
                    type="text"
                    name="name"
                    value={formData.name}
                    onChange={handleInputChange}
                    required
                    placeholder="e.g., Reno Events Center"
                    style={inputStyle}
                  />
                </div>
                {/* Address — full width, Places autocomplete */}
                <div style={{ gridColumn: "1 / -1" }}>
                  <label style={labelStyle}>Address *</label>
                  <LocationAutocomplete
                    value={formData.address}
                    onChange={(e) => setFormData(f => ({ ...f, address: e.target.value }))}
                    onPlaceSelect={({ formatted_address, city, latitude, longitude }) =>
                      setFormData(f => ({ ...f, address: formatted_address, city, latitude, longitude }))
                    }
                    style={inputStyle}
                    placeholder="Start typing an address…"
                    required
                    className=""
                  />
                  <p style={{ color: "#555", fontSize: "11px", marginTop: "5px" }}>
                    Pick a suggestion to auto-fill city, latitude &amp; longitude
                  </p>
                </div>

                {/* City */}
                <div style={{ gridColumn: "1 / -1" }}>
                  <label style={labelStyle}>City *</label>
                  <input
                    type="text"
                    name="city"
                    value={formData.city}
                    onChange={handleInputChange}
                    required
                    placeholder="e.g., Reno"
                    style={{ ...inputStyle, borderColor: formData.city ? "#ff00e0" : "#2a2a2a" }}
                  />
                </div>

                {/* Latitude */}
                <div>
                  <label style={{ ...labelStyle, display: "flex", alignItems: "center", gap: "6px" }}>
                    Latitude
                    {formData.latitude && <span style={{ color: "#ff00e0", fontSize: "10px", fontWeight: 700 }}>● AUTO</span>}
                  </label>
                  <input
                    type="number"
                    name="latitude"
                    value={formData.latitude}
                    onChange={handleInputChange}
                    step="any"
                    placeholder="Auto-filled from address"
                    style={{
                      ...inputStyle,
                      borderColor: formData.latitude ? "#ff00e0" : "#2a2a2a",
                      color: formData.latitude ? "#fff" : "#555",
                    }}
                  />
                </div>

                {/* Longitude */}
                <div>
                  <label style={{ ...labelStyle, display: "flex", alignItems: "center", gap: "6px" }}>
                    Longitude
                    {formData.longitude && <span style={{ color: "#ff00e0", fontSize: "10px", fontWeight: 700 }}>● AUTO</span>}
                  </label>
                  <input
                    type="number"
                    name="longitude"
                    value={formData.longitude}
                    onChange={handleInputChange}
                    step="any"
                    placeholder="Auto-filled from address"
                    style={{
                      ...inputStyle,
                      borderColor: formData.longitude ? "#ff00e0" : "#2a2a2a",
                      color: formData.longitude ? "#fff" : "#555",
                    }}
                  />
                </div>

                {/* Phone */}
                <div>
                  <label style={labelStyle}>Phone</label>
                  <input
                    type="tel"
                    name="phone"
                    value={formData.phone}
                    onChange={handleInputChange}
                    placeholder="e.g., (775) 123-4567"
                    style={inputStyle}
                  />
                </div>

                {/* Capacity */}
                <div>
                  <label style={labelStyle}>Capacity</label>
                  <input
                    type="number"
                    name="capacity"
                    value={formData.capacity}
                    onChange={handleInputChange}
                    placeholder="e.g., 1000"
                    style={inputStyle}
                  />
                </div>

                {/* Website — full width */}
                <div style={{ gridColumn: "1 / -1" }}>
                  <label style={labelStyle}>Website</label>
                  <input
                    type="url"
                    name="website"
                    value={formData.website}
                    onChange={handleInputChange}
                    placeholder="e.g., https://example.com"
                    style={inputStyle}
                  />
                </div>
                <div style={{ gridColumn: "1 / -1" }}>
                  <label style={labelStyle}>Description</label>
                  <textarea
                    name="description"
                    value={formData.description}
                    onChange={handleInputChange}
                    rows={3}
                    placeholder="Describe the venue..."
                    style={{ ...inputStyle, resize: "vertical" }}
                  />
                </div>
              </div>

              <div style={{ display: "flex", gap: "8px" }}>
                <button
                  type="submit"
                  disabled={submitting}
                  style={{
                    padding: "8px 16px",
                    borderRadius: "6px",
                    border: "none",
                    background: "#ff00e0",
                    color: "#fff",
                    fontSize: "13px",
                    fontWeight: 600,
                    cursor: "pointer",
                    opacity: submitting ? 0.5 : 1,
                  }}
                >
                  {submitting ? "..." : (editingVenue ? "Update" : "Create")}
                </button>
                <button
                  type="button"
                  onClick={handleCancel}
                  style={{
                    padding: "8px 16px",
                    borderRadius: "6px",
                    border: "1px solid #666",
                    background: "transparent",
                    color: "#999",
                    fontSize: "13px",
                    fontWeight: 600,
                    cursor: "pointer",
                  }}
                >
                  Cancel
                </button>
              </div>
            </form>
          </div>
        )}

        {/* Venues Table */}
        <div className="rounded-xl overflow-hidden" style={{ background: "#1d191e", border: "1px solid #2a2a2a" }}>
          {loading ? (
            <div className="flex justify-center py-16">
              <div className="w-10 h-10 rounded-full border-2 border-transparent animate-spin"
                style={{ borderTopColor: "#ff00e0", borderRightColor: "#ff00e0" }} />
            </div>
          ) : venues.length === 0 ? (
            <div className="text-center py-24">
              <p className="text-white font-semibold">No venues created</p>
              <p className="text-gray-500 text-sm mt-1">Create your first venue to get started</p>
            </div>
          ) : (
            <div className="overflow-x-auto">
              <table style={{ width: "100%", borderCollapse: "collapse" }}>
                <thead>
                  <tr style={{ borderBottom: "1px solid #2a2a2a" }}>
                    <th style={{ padding: "16px", textAlign: "left", color: "#666", fontSize: "12px", fontWeight: 600 }}>Name</th>
                    <th style={{ padding: "16px", textAlign: "left", color: "#666", fontSize: "12px", fontWeight: 600 }}>City</th>
                    <th style={{ padding: "16px", textAlign: "left", color: "#666", fontSize: "12px", fontWeight: 600 }}>Address</th>
                    <th style={{ padding: "16px", textAlign: "left", color: "#666", fontSize: "12px", fontWeight: 600 }}>Phone</th>
                    <th style={{ padding: "16px", textAlign: "left", color: "#666", fontSize: "12px", fontWeight: 600 }}>Capacity</th>
                    <th style={{ padding: "16px", textAlign: "left", color: "#666", fontSize: "12px", fontWeight: 600 }}>Actions</th>
                  </tr>
                </thead>
                <tbody>
                  {paginatedVenues.map((venue, i) => (
                    <tr
                      key={venue.id}
                      style={{ borderBottom: i < paginatedVenues.length - 1 ? "1px solid #252525" : "none" }}
                    >
                      <td style={{ padding: "16px" }}>
                        <p className="font-semibold text-white">{venue.name}</p>
                      </td>
                      <td style={{ padding: "16px" }}>
                        <p className="text-gray-400 text-sm">{venue.city}</p>
                      </td>
                      <td style={{ padding: "16px" }}>
                        <p className="text-gray-400 text-sm">{venue.address}</p>
                      </td>
                      <td style={{ padding: "16px" }}>
                        <p className="text-gray-400 text-sm">{venue.phone || "—"}</p>
                      </td>
                      <td style={{ padding: "16px" }}>
                        <p className="text-white text-sm">{venue.capacity ? venue.capacity.toLocaleString() : "—"}</p>
                      </td>
                      <td style={{ padding: "16px" }}>
                        <div style={{ display: "flex", gap: "8px" }}>
                          <button
                            onClick={() => handleEdit(venue)}
                            style={{
                              padding: "6px 12px",
                              fontSize: "11px",
                              fontWeight: 600,
                              borderRadius: "4px",
                              border: "1px solid #ff00e0",
                              background: "transparent",
                              color: "#ff00e0",
                              cursor: "pointer",
                            }}
                          >
                            Edit
                          </button>
                          <button
                            onClick={() => handleDelete(venue.id)}
                            disabled={actioningId === venue.id}
                            style={{
                              padding: "6px 12px",
                              fontSize: "11px",
                              fontWeight: 600,
                              borderRadius: "4px",
                              border: "1px solid #666",
                              background: "transparent",
                              color: "#999",
                              cursor: "pointer",
                              opacity: actioningId === venue.id ? 0.5 : 1,
                            }}
                          >
                            {actioningId === venue.id ? "..." : "Delete"}
                          </button>
                        </div>
                      </td>
                    </tr>
                  ))}
                </tbody>
              </table>
            </div>
          )}
        </div>

        {/* Pagination */}
        {!loading && venues.length > 0 && (
          <div style={{
            marginTop: "24px",
            display: "flex",
            justifyContent: "space-between",
            alignItems: "center",
            padding: "16px",
            background: "#1d191e",
            borderRadius: "6px",
            border: "1px solid #2a2a2a",
          }}>
            <div style={{ color: "#999", fontSize: "13px" }}>
              Page <span style={{ color: "#ff00e0", fontWeight: 600 }}>{currentPage}</span> of{" "}
              <span style={{ color: "#ff00e0", fontWeight: 600 }}>{totalPages || 1}</span> • Showing{" "}
              <span style={{ color: "#ff00e0", fontWeight: 600 }}>{paginatedVenues.length}</span> of{" "}
              <span style={{ color: "#ff00e0", fontWeight: 600 }}>{venues.length}</span> venues
            </div>
            <div style={{ display: "flex", gap: "8px" }}>
              <button
                onClick={() => setCurrentPage((p) => Math.max(1, p - 1))}
                disabled={currentPage === 1}
                style={{
                  padding: "8px 16px",
                  borderRadius: "4px",
                  border: "1px solid #2a2a2a",
                  background: currentPage === 1 ? "#0a0a0a" : "#1d191e",
                  color: currentPage === 1 ? "#444" : "#e0e0e0",
                  fontSize: "12px",
                  fontWeight: 600,
                  cursor: currentPage === 1 ? "not-allowed" : "pointer",
                  opacity: currentPage === 1 ? 0.5 : 1,
                }}
              >
                ← Previous
              </button>
              <button
                onClick={() => setCurrentPage((p) => Math.min(totalPages, p + 1))}
                disabled={currentPage >= totalPages}
                style={{
                  padding: "8px 16px",
                  borderRadius: "4px",
                  border: "1px solid #2a2a2a",
                  background: currentPage >= totalPages ? "#0a0a0a" : "#1d191e",
                  color: currentPage >= totalPages ? "#444" : "#e0e0e0",
                  fontSize: "12px",
                  fontWeight: 600,
                  cursor: currentPage >= totalPages ? "not-allowed" : "pointer",
                  opacity: currentPage >= totalPages ? 0.5 : 1,
                }}
              >
                Next →
              </button>
            </div>
          </div>
        )}
      </div>
    </div>
  );
}
